starter:
.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 1rem;
}
.grid img {
  width: 100%;
  height: 200px;
  /* Add object-fit here */
}

.product-img {
  width: 100%;
  height: 250px;
  background: #f5f5f5;
  /* Add object-fit here */
}
.product-img img {
  width: 100%;
  height: 100%;
  object-fit: contain;
}

.portrait-grid img {
  width: 100%;
  height: 300px;
  object-fit: cover;
  /* Add object-position here */
}

.hero { position: relative; height: 100vh; overflow: hidden; }
.hero video {
  position: absolute;
  width: 100%; height: 100%;
  /* Add object-fit here */
}
